INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('bulk-single-0001', 'teacher-1', 'Java 基础', 'StringBuilder', '易', 'single', '扩展单选：StringBuilder的核心作用是什么？', '["泛型用于在编译期约束集合或方法的类型，在公共工具类和集合返回值声明时可以提升实现的清晰度和稳定性。","try-catch-finally用于捕获异常并保证必要清理逻辑执行，在文件读取、网络请求和事务处理时可以提升实现的清晰度和稳定性。","enum用于表达固定且有限的业务状态，在考试状态、题型和用户角色建模时可以提升实现的清晰度和稳定性。","StringBuilder用于高效拼接可变字符串，在循环拼接日志或 SQL 片段时可以提升实现的清晰度和稳定性。"]', '["StringBuilder用于高效拼接可变字符串，在循环拼接日志或 SQL 片段时可以提升实现的清晰度和稳定性。"]', 4, 'bulk-choice-20260506') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('bulk-single-0002', 'teacher-1', 'Java 基础', 'StringBuilder', '易', 'single', '扩展单选：StringBuilder更适合应用在哪个场景？', '["try-catch-finally适合用于文件读取、网络请求和事务处理。","enum适合用于考试状态、题型和用户角色建模。","StringBuilder适合用于循环拼接日志或 SQL 片段。","泛型适合用于公共工具类和集合返回值声明。"]', '["StringBuilder适合用于循环拼接日志或 SQL 片段。"]', 4, 'bulk-choice-20260506') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('bulk-single-0003', 'teacher-1', 'Java 基础', 'StringBuilder', '中', 'single', '扩展单选：学习StringBuilder时应重点理解哪一项？', '["StringBuilder只和页面颜色有关，与业务逻辑无关。","应重点理解 append 及其在业务代码中的使用边界。","只需要记住 StringBuilder 的中文名称即可，不必理解使用条件。","StringBuilder主要用于绕过接口参数校验。"]', '["应重点理解 append 及其在业务代码中的使用边界。"]', 4, 'bulk-choice-20260506') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('bulk-single-0004', 'teacher-1', 'Java 基础', 'StringBuilder', '易', 'single', '扩展单选：关于StringBuilder的说法，哪一项属于常见误区？', '["StringBuilder会自动绕过登录和权限校验，因此不需要鉴权设计","StringBuilder能够高效拼接可变字符串","常见应用场景包括循环拼接日志或 SQL 片段","理解 append 有助于掌握 StringBuilder 的核心用法"]', '["StringBuilder会自动绕过登录和权限校验，因此不需要鉴权设计"]', 4, 'bulk-choice-20260506') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('bulk-single-0005', 'teacher-1', 'Java 基础', 'StringBuilder', '易', 'single', '扩展单选：在教师端维护题库时，StringBuilder带来的主要价值是？', '["让所有题目自动变成满分答案。","强制删除学生的历史答题记录。","完全替代数据库和接口设计。","帮助教师端功能保持结构清晰，并降低后续维护成本。"]', '["帮助教师端功能保持结构清晰，并降低后续维护成本。"]', 4, 'bulk-choice-20260506') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('bulk-single-0006', 'teacher-1', 'Java 基础', 'StringBuilder', '中', 'single', '扩展单选：使用StringBuilder时更合理的工程做法是？', '["把所有页面逻辑都写进一个超长函数。","只在出现线上故障后再补充异常处理。","使用 StringBuilder 时应结合边界条件、异常处理和输入校验","不做输入校验，直接信任所有客户端数据。"]', '["使用 StringBuilder 时应结合边界条件、异常处理和输入校验"]', 4, 'bulk-choice-20260506') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('bulk-single-0007', 'teacher-1', 'Java 基础', 'StringBuilder', '易', 'single', '扩展单选：StringBuilder与在线考试业务结合时，优先关注什么？', '["优先把所有账号密码写在页面脚本中。","优先关注角色权限、数据一致性、异常提示和可追踪日志。","优先隐藏所有错误信息，使用户无法判断操作结果。","优先跳过后端校验，只依赖前端按钮禁用。"]', '["优先关注角色权限、数据一致性、异常提示和可追踪日志。"]', 4, 'bulk-choice-20260506') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('bulk-single-0008', 'teacher-1', 'Java 基础', 'StringBuilder', '易', 'single', '扩展单选：StringBuilder相关实现需要避免哪种问题？', '["需要避免职责混乱、重复代码和缺少失败分支处理。","需要避免任何日志记录，因为日志一定会导致系统不可用。","需要避免所有参数校验，因为校验会让功能无法运行。","需要避免接口返回明确状态，因为状态码没有意义。"]', '["需要避免职责混乱、重复代码和缺少失败分支处理。"]', 4, 'bulk-choice-20260506') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('bulk-single-0009', 'teacher-1', 'Java 基础', 'StringBuilder', '中', 'single', '扩展单选：如果要验证StringBuilder实现是否可靠，最应检查哪项？', '["只检查按钮颜色是否足够醒目。","只检查文件名是否足够短。","只检查是否删除了所有历史数据。","检查正常流程、异常流程、边界输入和权限范围是否都有覆盖。"]', '["检查正常流程、异常流程、边界输入和权限范围是否都有覆盖。"]', 4, 'bulk-choice-20260506') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
