INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('bulk-single-0020', 'teacher-1', 'Java 基础', '泛型', '易', 'single', '扩展单选：关于泛型的知识点归类，哪一项最准确？', '["泛型属于Java 基础 / 泛型相关知识点。","泛型只属于图片处理知识点，与软件开发无关。","泛型只属于线下阅卷规则，与系统实现无关。","泛型只属于硬件采购流程，与代码设计无关。"]', '["泛型属于Java 基础 / 泛型相关知识点。"]', 4, 'bulk-choice-20260506') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('bulk-single-0021', 'teacher-1', 'Java 基础', '异常处理', '中', 'single', '扩展单选：try-catch-finally的核心作用是什么？', '["StringBuilder用于高效拼接可变字符串，在循环拼接日志或 SQL 片段时可以提升实现的清晰度和稳定性。","泛型用于在编译期约束集合或方法的类型，在公共工具类和集合返回值声明时可以提升实现的清晰度和稳定性。","enum用于表达固定且有限的业务状态，在考试状态、题型和用户角色建模时可以提升实现的清晰度和稳定性。","try-catch-finally用于捕获异常并保证必要清理逻辑执行，在文件读取、网络请求和事务处理时可以提升实现的清晰度和稳定性。"]', '["try-catch-finally用于捕获异常并保证必要清理逻辑执行，在文件读取、网络请求和事务处理时可以提升实现的清晰度和稳定性。"]', 4, 'bulk-choice-20260506') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('bulk-single-0022', 'teacher-1', 'Java 基础', '异常处理', '易', 'single', '扩展单选：try-catch-finally更适合应用在哪个场景？', '["泛型适合用于公共工具类和集合返回值声明。","enum适合用于考试状态、题型和用户角色建模。","try-catch-finally适合用于文件读取、网络请求和事务处理。","StringBuilder适合用于循环拼接日志或 SQL 片段。"]', '["try-catch-finally适合用于文件读取、网络请求和事务处理。"]', 4, 'bulk-choice-20260506') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('bulk-single-0023', 'teacher-1', 'Java 基础', '异常处理', '易', 'single', '扩展单选：学习try-catch-finally时应重点理解哪一项？', '["try-catch-finally只和页面颜色有关，与业务逻辑无关。","应重点理解 finally 及其在业务代码中的使用边界。","只需要记住 try-catch-finally 的中文名称即可，不必理解使用条件。","try-catch-finally主要用于绕过接口参数校验。"]', '["应重点理解 finally 及其在业务代码中的使用边界。"]', 4, 'bulk-choice-20260506') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('bulk-single-0024', 'teacher-1', 'Java 基础', '异常处理', '中', 'single', '扩展单选：关于try-catch-finally的说法，哪一项属于常见误区？', '["try-catch-finally会自动绕过登录和权限校验，因此不需要鉴权设计","try-catch-finally能够捕获异常并保证必要清理逻辑执行","常见应用场景包括文件读取、网络请求和事务处理","理解 finally 有助于掌握 try-catch-finally 的核心用法"]', '["try-catch-finally会自动绕过登录和权限校验，因此不需要鉴权设计"]', 4, 'bulk-choice-20260506') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('bulk-single-0025', 'teacher-1', 'Java 基础', '异常处理', '易', 'single', '扩展单选：在教师端维护题库时，try-catch-finally带来的主要价值是？', '["让所有题目自动变成满分答案。","强制删除学生的历史答题记录。","完全替代数据库和接口设计。","帮助教师端功能保持结构清晰，并降低后续维护成本。"]', '["帮助教师端功能保持结构清晰，并降低后续维护成本。"]', 4, 'bulk-choice-20260506') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('bulk-single-0026', 'teacher-1', 'Java 基础', '异常处理', '易', 'single', '扩展单选：使用try-catch-finally时更合理的工程做法是？', '["把所有页面逻辑都写进一个超长函数。","只在出现线上故障后再补充异常处理。","使用 try-catch-finally 时应结合边界条件、异常处理和输入校验","不做输入校验，直接信任所有客户端数据。"]', '["使用 try-catch-finally 时应结合边界条件、异常处理和输入校验"]', 4, 'bulk-choice-20260506') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
