INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('bulk-single-0097', 'teacher-1', 'Java 集合', 'HashMap', '易', 'single', '扩展单选：HashMap与在线考试业务结合时，优先关注什么？', '["优先隐藏所有错误信息，使用户无法判断操作结果。","优先跳过后端校验，只依赖前端按钮禁用。","优先把所有账号密码写在页面脚本中。","优先关注角色权限、数据一致性、异常提示和可追踪日志。"]', '["优先关注角色权限、数据一致性、异常提示和可追踪日志。"]', 4, 'bulk-choice-20260506') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('bulk-single-0098', 'teacher-1', 'Java 集合', 'HashMap', '易', 'single', '扩展单选：HashMap相关实现需要避免哪种问题？', '["需要避免所有参数校验，因为校验会让功能无法运行。","需要避免接口返回明确状态，因为状态码没有意义。","需要避免职责混乱、重复代码和缺少失败分支处理。","需要避免任何日志记录，因为日志一定会导致系统不可用。"]', '["需要避免职责混乱、重复代码和缺少失败分支处理。"]', 4, 'bulk-choice-20260506') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('bulk-single-0099', 'teacher-1', 'Java 集合', 'HashMap', '中', 'single', '扩展单选：如果要验证HashMap实现是否可靠，最应检查哪项？', '["只检查是否删除了所有历史数据。","检查正常流程、异常流程、边界输入和权限范围是否都有覆盖。","只检查按钮颜色是否足够醒目。","只检查文件名是否足够短。"]', '["检查正常流程、异常流程、边界输入和权限范围是否都有覆盖。"]', 4, 'bulk-choice-20260506') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('bulk-single-0100', 'teacher-1', 'Java 集合', 'HashMap', '易', 'single', '扩展单选：关于HashMap的知识点归类，哪一项最准确？', '["HashMap属于Java 集合 / HashMap相关知识点。","HashMap只属于图片处理知识点，与软件开发无关。","HashMap只属于线下阅卷规则，与系统实现无关。","HashMap只属于硬件采购流程，与代码设计无关。"]', '["HashMap属于Java 集合 / HashMap相关知识点。"]', 4, 'bulk-choice-20260506') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('bulk-single-0101', 'teacher-1', 'Java 集合', 'HashSet', '易', 'single', '扩展单选：HashSet的核心作用是什么？', '["StringBuilder用于高效拼接可变字符串，在循环拼接日志或 SQL 片段时可以提升实现的清晰度和稳定性。","泛型用于在编译期约束集合或方法的类型，在公共工具类和集合返回值声明时可以提升实现的清晰度和稳定性。","try-catch-finally用于捕获异常并保证必要清理逻辑执行，在文件读取、网络请求和事务处理时可以提升实现的清晰度和稳定性。","HashSet用于保存不重复元素并完成去重，在导入账号、标签集合和名单去重时可以提升实现的清晰度和稳定性。"]', '["HashSet用于保存不重复元素并完成去重，在导入账号、标签集合和名单去重时可以提升实现的清晰度和稳定性。"]', 4, 'bulk-choice-20260506') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
