INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('bulk-single-0131', 'teacher-1', 'Java 并发', '线程池', '易', 'single', '扩展单选：ThreadPoolExecutor的核心作用是什么？', '["try-catch-finally用于捕获异常并保证必要清理逻辑执行，在文件读取、网络请求和事务处理时可以提升实现的清晰度和稳定性。","ThreadPoolExecutor用于复用线程并统一调度异步任务，在批量导出、异步通知和后台计算时可以提升实现的清晰度和稳定性。","StringBuilder用于高效拼接可变字符串，在循环拼接日志或 SQL 片段时可以提升实现的清晰度和稳定性。","泛型用于在编译期约束集合或方法的类型，在公共工具类和集合返回值声明时可以提升实现的清晰度和稳定性。"]', '["ThreadPoolExecutor用于复用线程并统一调度异步任务，在批量导出、异步通知和后台计算时可以提升实现的清晰度和稳定性。"]', 4, 'bulk-choice-20260506') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
