INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('bulk-single-0134', 'teacher-1', 'Java 并发', '线程池', '易', 'single', '扩展单选：关于ThreadPoolExecutor的说法，哪一项属于常见误区？', '["常见应用场景包括批量导出、异步通知和后台计算","理解 submit 有助于掌握 ThreadPoolExecutor 的核心用法","ThreadPoolExecutor会自动绕过登录和权限校验，因此不需要鉴权设计","ThreadPoolExecutor能够复用线程并统一调度异步任务"]', '["ThreadPoolExecutor会自动绕过登录和权限校验，因此不需要鉴权设计"]', 4, 'bulk-choice-20260506') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
