INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('bulk-single-0230', 'teacher-1', 'JVM', 'JIT', '易', 'single', '扩展单选：关于JIT 编译的知识点归类，哪一项最准确？', '["JIT 编译只属于线下阅卷规则，与系统实现无关。","JIT 编译只属于硬件采购流程，与代码设计无关。","JIT 编译属于JVM / JIT相关知识点。","JIT 编译只属于图片处理知识点，与软件开发无关。"]', '["JIT 编译属于JVM / JIT相关知识点。"]', 4, 'bulk-choice-20260506') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('bulk-single-0231', 'teacher-1', '数据库', '事务隔离', '中', 'single', '扩展单选：事务隔离级别的核心作用是什么？', '["try-catch-finally用于捕获异常并保证必要清理逻辑执行，在文件读取、网络请求和事务处理时可以提升实现的清晰度和稳定性。","事务隔离级别用于控制并发事务之间的数据可见性，在解决脏读、不可重复读和幻读问题时可以提升实现的清晰度和稳定性。","StringBuilder用于高效拼接可变字符串，在循环拼接日志或 SQL 片段时可以提升实现的清晰度和稳定性。","泛型用于在编译期约束集合或方法的类型，在公共工具类和集合返回值声明时可以提升实现的清晰度和稳定性。"]', '["事务隔离级别用于控制并发事务之间的数据可见性，在解决脏读、不可重复读和幻读问题时可以提升实现的清晰度和稳定性。"]', 4, 'bulk-choice-20260506') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('bulk-single-0232', 'teacher-1', '数据库', '事务隔离', '易', 'single', '扩展单选：事务隔离级别更适合应用在哪个场景？', '["事务隔离级别适合用于解决脏读、不可重复读和幻读问题。","StringBuilder适合用于循环拼接日志或 SQL 片段。","泛型适合用于公共工具类和集合返回值声明。","try-catch-finally适合用于文件读取、网络请求和事务处理。"]', '["事务隔离级别适合用于解决脏读、不可重复读和幻读问题。"]', 4, 'bulk-choice-20260506') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('bulk-single-0233', 'teacher-1', '数据库', '事务隔离', '易', 'single', '扩展单选：学习事务隔离级别时应重点理解哪一项？', '["只需要记住 事务隔离级别 的中文名称即可，不必理解使用条件。","事务隔离级别主要用于绕过接口参数校验。","事务隔离级别只和页面颜色有关，与业务逻辑无关。","应重点理解 Isolation 及其在业务代码中的使用边界。"]', '["应重点理解 Isolation 及其在业务代码中的使用边界。"]', 4, 'bulk-choice-20260506') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('bulk-single-0234', 'teacher-1', '数据库', '事务隔离', '中', 'single', '扩展单选：关于事务隔离级别的说法，哪一项属于常见误区？', '["常见应用场景包括解决脏读、不可重复读和幻读问题","理解 Isolation 有助于掌握 事务隔离级别 的核心用法","事务隔离级别会自动绕过登录和权限校验，因此不需要鉴权设计","事务隔离级别能够控制并发事务之间的数据可见性"]', '["事务隔离级别会自动绕过登录和权限校验，因此不需要鉴权设计"]', 4, 'bulk-choice-20260506') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('bulk-single-0235', 'teacher-1', '数据库', '事务隔离', '易', 'single', '扩展单选：在教师端维护题库时，事务隔离级别带来的主要价值是？', '["完全替代数据库和接口设计。","帮助教师端功能保持结构清晰，并降低后续维护成本。","让所有题目自动变成满分答案。","强制删除学生的历史答题记录。"]', '["帮助教师端功能保持结构清晰，并降低后续维护成本。"]', 4, 'bulk-choice-20260506') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('bulk-single-0236', 'teacher-1', '数据库', '事务隔离', '易', 'single', '扩展单选：使用事务隔离级别时更合理的工程做法是？', '["使用 事务隔离级别 时应结合边界条件、异常处理和输入校验","不做输入校验，直接信任所有客户端数据。","把所有页面逻辑都写进一个超长函数。","只在出现线上故障后再补充异常处理。"]', '["使用 事务隔离级别 时应结合边界条件、异常处理和输入校验"]', 4, 'bulk-choice-20260506') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('bulk-single-0237', 'teacher-1', '数据库', '事务隔离', '中', 'single', '扩展单选：事务隔离级别与在线考试业务结合时，优先关注什么？', '["优先隐藏所有错误信息，使用户无法判断操作结果。","优先跳过后端校验，只依赖前端按钮禁用。","优先把所有账号密码写在页面脚本中。","优先关注角色权限、数据一致性、异常提示和可追踪日志。"]', '["优先关注角色权限、数据一致性、异常提示和可追踪日志。"]', 4, 'bulk-choice-20260506') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
