INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('bulk-single-0248', 'teacher-1', '数据库', '索引', '易', 'single', '扩展单选：B+Tree 索引相关实现需要避免哪种问题？', '["需要避免职责混乱、重复代码和缺少失败分支处理。","需要避免任何日志记录，因为日志一定会导致系统不可用。","需要避免所有参数校验，因为校验会让功能无法运行。","需要避免接口返回明确状态，因为状态码没有意义。"]', '["需要避免职责混乱、重复代码和缺少失败分支处理。"]', 4, 'bulk-choice-20260506') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('bulk-single-0249', 'teacher-1', '数据库', '索引', '中', 'single', '扩展单选：如果要验证B+Tree 索引实现是否可靠，最应检查哪项？', '["只检查按钮颜色是否足够醒目。","只检查文件名是否足够短。","只检查是否删除了所有历史数据。","检查正常流程、异常流程、边界输入和权限范围是否都有覆盖。"]', '["检查正常流程、异常流程、边界输入和权限范围是否都有覆盖。"]', 4, 'bulk-choice-20260506') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('bulk-single-0250', 'teacher-1', '数据库', '索引', '易', 'single', '扩展单选：关于B+Tree 索引的知识点归类，哪一项最准确？', '["B+Tree 索引只属于线下阅卷规则，与系统实现无关。","B+Tree 索引只属于硬件采购流程，与代码设计无关。","B+Tree 索引属于数据库 / 索引相关知识点。","B+Tree 索引只属于图片处理知识点，与软件开发无关。"]', '["B+Tree 索引属于数据库 / 索引相关知识点。"]', 4, 'bulk-choice-20260506') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('bulk-single-0251', 'teacher-1', '数据库', '联合索引', '易', 'single', '扩展单选：联合索引的核心作用是什么？', '["try-catch-finally用于捕获异常并保证必要清理逻辑执行，在文件读取、网络请求和事务处理时可以提升实现的清晰度和稳定性。","联合索引用于按多个字段组合建立查询加速路径，在班级、考试、状态组合筛选时可以提升实现的清晰度和稳定性。","StringBuilder用于高效拼接可变字符串，在循环拼接日志或 SQL 片段时可以提升实现的清晰度和稳定性。","泛型用于在编译期约束集合或方法的类型，在公共工具类和集合返回值声明时可以提升实现的清晰度和稳定性。"]', '["联合索引用于按多个字段组合建立查询加速路径，在班级、考试、状态组合筛选时可以提升实现的清晰度和稳定性。"]', 4, 'bulk-choice-20260506') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('bulk-single-0252', 'teacher-1', '数据库', '联合索引', '中', 'single', '扩展单选：联合索引更适合应用在哪个场景？', '["联合索引适合用于班级、考试、状态组合筛选。","StringBuilder适合用于循环拼接日志或 SQL 片段。","泛型适合用于公共工具类和集合返回值声明。","try-catch-finally适合用于文件读取、网络请求和事务处理。"]', '["联合索引适合用于班级、考试、状态组合筛选。"]', 4, 'bulk-choice-20260506') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('bulk-single-0253', 'teacher-1', '数据库', '联合索引', '易', 'single', '扩展单选：学习联合索引时应重点理解哪一项？', '["只需要记住 联合索引 的中文名称即可，不必理解使用条件。","联合索引主要用于绕过接口参数校验。","联合索引只和页面颜色有关，与业务逻辑无关。","应重点理解 最左前缀 及其在业务代码中的使用边界。"]', '["应重点理解 最左前缀 及其在业务代码中的使用边界。"]', 4, 'bulk-choice-20260506') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('bulk-single-0254', 'teacher-1', '数据库', '联合索引', '易', 'single', '扩展单选：关于联合索引的说法，哪一项属于常见误区？', '["常见应用场景包括班级、考试、状态组合筛选","理解 最左前缀 有助于掌握 联合索引 的核心用法","联合索引会自动绕过登录和权限校验，因此不需要鉴权设计","联合索引能够按多个字段组合建立查询加速路径"]', '["联合索引会自动绕过登录和权限校验，因此不需要鉴权设计"]', 4, 'bulk-choice-20260506') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
