INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('bulk-single-0303', 'teacher-1', 'Web', 'HTTP 状态码', '中', 'single', '扩展单选：学习HTTP 状态码时应重点理解哪一项？', '["HTTP 状态码只和页面颜色有关，与业务逻辑无关。","应重点理解 200/401/404 及其在业务代码中的使用边界。","只需要记住 HTTP 状态码 的中文名称即可，不必理解使用条件。","HTTP 状态码主要用于绕过接口参数校验。"]', '["应重点理解 200/401/404 及其在业务代码中的使用边界。"]', 4, 'bulk-choice-20260506') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
