INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('bulk-single-0323', 'teacher-1', 'Web', 'Session', '易', 'single', '扩展单选：学习Session时应重点理解哪一项？', '["Session只和页面颜色有关，与业务逻辑无关。","应重点理解 sessionId 及其在业务代码中的使用边界。","只需要记住 Session 的中文名称即可，不必理解使用条件。","Session主要用于绕过接口参数校验。"]', '["应重点理解 sessionId 及其在业务代码中的使用边界。"]', 4, 'bulk-choice-20260506') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
