INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('bulk-single-0325', 'teacher-1', 'Web', 'Session', '易', 'single', '扩展单选：在教师端维护题库时，Session带来的主要价值是？', '["让所有题目自动变成满分答案。","强制删除学生的历史答题记录。","完全替代数据库和接口设计。","帮助教师端功能保持结构清晰，并降低后续维护成本。"]', '["帮助教师端功能保持结构清晰，并降低后续维护成本。"]', 4, 'bulk-choice-20260506') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('bulk-single-0326', 'teacher-1', 'Web', 'Session', '易', 'single', '扩展单选：使用Session时更合理的工程做法是？', '["把所有页面逻辑都写进一个超长函数。","只在出现线上故障后再补充异常处理。","使用 Session 时应结合边界条件、异常处理和输入校验","不做输入校验，直接信任所有客户端数据。"]', '["使用 Session 时应结合边界条件、异常处理和输入校验"]', 4, 'bulk-choice-20260506') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('bulk-single-0327', 'teacher-1', 'Web', 'Session', '中', 'single', '扩展单选：Session与在线考试业务结合时，优先关注什么？', '["优先把所有账号密码写在页面脚本中。","优先关注角色权限、数据一致性、异常提示和可追踪日志。","优先隐藏所有错误信息，使用户无法判断操作结果。","优先跳过后端校验，只依赖前端按钮禁用。"]', '["优先关注角色权限、数据一致性、异常提示和可追踪日志。"]', 4, 'bulk-choice-20260506') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('bulk-single-0328', 'teacher-1', 'Web', 'Session', '易', 'single', '扩展单选：Session相关实现需要避免哪种问题？', '["需要避免职责混乱、重复代码和缺少失败分支处理。","需要避免任何日志记录，因为日志一定会导致系统不可用。","需要避免所有参数校验，因为校验会让功能无法运行。","需要避免接口返回明确状态，因为状态码没有意义。"]', '["需要避免职责混乱、重复代码和缺少失败分支处理。"]', 4, 'bulk-choice-20260506') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('bulk-single-0329', 'teacher-1', 'Web', 'Session', '易', 'single', '扩展单选：如果要验证Session实现是否可靠，最应检查哪项？', '["只检查按钮颜色是否足够醒目。","只检查文件名是否足够短。","只检查是否删除了所有历史数据。","检查正常流程、异常流程、边界输入和权限范围是否都有覆盖。"]', '["检查正常流程、异常流程、边界输入和权限范围是否都有覆盖。"]', 4, 'bulk-choice-20260506') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('bulk-single-0330', 'teacher-1', 'Web', 'Session', '中', 'single', '扩展单选：关于Session的知识点归类，哪一项最准确？', '["Session只属于线下阅卷规则，与系统实现无关。","Session只属于硬件采购流程，与代码设计无关。","Session属于Web / Session相关知识点。","Session只属于图片处理知识点，与软件开发无关。"]', '["Session属于Web / Session相关知识点。"]', 4, 'bulk-choice-20260506') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('bulk-single-0331', 'teacher-1', 'Web', 'JWT', '易', 'single', '扩展单选：JWT的核心作用是什么？', '["try-catch-finally用于捕获异常并保证必要清理逻辑执行，在文件读取、网络请求和事务处理时可以提升实现的清晰度和稳定性。","JWT用于用签名令牌携带可验证的身份声明，在前后端分离接口鉴权时可以提升实现的清晰度和稳定性。","StringBuilder用于高效拼接可变字符串，在循环拼接日志或 SQL 片段时可以提升实现的清晰度和稳定性。","泛型用于在编译期约束集合或方法的类型，在公共工具类和集合返回值声明时可以提升实现的清晰度和稳定性。"]', '["JWT用于用签名令牌携带可验证的身份声明，在前后端分离接口鉴权时可以提升实现的清晰度和稳定性。"]', 4, 'bulk-choice-20260506') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('bulk-single-0332', 'teacher-1', 'Web', 'JWT', '易', 'single', '扩展单选：JWT更适合应用在哪个场景？', '["JWT适合用于前后端分离接口鉴权。","StringBuilder适合用于循环拼接日志或 SQL 片段。","泛型适合用于公共工具类和集合返回值声明。","try-catch-finally适合用于文件读取、网络请求和事务处理。"]', '["JWT适合用于前后端分离接口鉴权。"]', 4, 'bulk-choice-20260506') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
