INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('bulk-single-0420', 'teacher-1', 'Spring', 'Validation', '中', 'single', '扩展单选：关于参数校验的知识点归类，哪一项最准确？', '["参数校验属于Spring / Validation相关知识点。","参数校验只属于图片处理知识点，与软件开发无关。","参数校验只属于线下阅卷规则，与系统实现无关。","参数校验只属于硬件采购流程，与代码设计无关。"]', '["参数校验属于Spring / Validation相关知识点。"]', 4, 'bulk-choice-20260506') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('bulk-single-0421', 'teacher-1', '前端', 'Vue 响应式', '易', 'single', '扩展单选：Vue 响应式的核心作用是什么？', '["StringBuilder用于高效拼接可变字符串，在循环拼接日志或 SQL 片段时可以提升实现的清晰度和稳定性。","泛型用于在编译期约束集合或方法的类型，在公共工具类和集合返回值声明时可以提升实现的清晰度和稳定性。","try-catch-finally用于捕获异常并保证必要清理逻辑执行，在文件读取、网络请求和事务处理时可以提升实现的清晰度和稳定性。","Vue 响应式用于让状态变化自动驱动界面更新，在筛选条件变化后刷新题目列表时可以提升实现的清晰度和稳定性。"]', '["Vue 响应式用于让状态变化自动驱动界面更新，在筛选条件变化后刷新题目列表时可以提升实现的清晰度和稳定性。"]', 4, 'bulk-choice-20260506') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('bulk-single-0422', 'teacher-1', '前端', 'Vue 响应式', '易', 'single', '扩展单选：Vue 响应式更适合应用在哪个场景？', '["泛型适合用于公共工具类和集合返回值声明。","try-catch-finally适合用于文件读取、网络请求和事务处理。","Vue 响应式适合用于筛选条件变化后刷新题目列表。","StringBuilder适合用于循环拼接日志或 SQL 片段。"]', '["Vue 响应式适合用于筛选条件变化后刷新题目列表。"]', 4, 'bulk-choice-20260506') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('bulk-single-0423', 'teacher-1', '前端', 'Vue 响应式', '中', 'single', '扩展单选：学习Vue 响应式时应重点理解哪一项？', '["Vue 响应式只和页面颜色有关，与业务逻辑无关。","应重点理解 ref/reactive 及其在业务代码中的使用边界。","只需要记住 Vue 响应式 的中文名称即可，不必理解使用条件。","Vue 响应式主要用于绕过接口参数校验。"]', '["应重点理解 ref/reactive 及其在业务代码中的使用边界。"]', 4, 'bulk-choice-20260506') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('bulk-single-0424', 'teacher-1', '前端', 'Vue 响应式', '易', 'single', '扩展单选：关于Vue 响应式的说法，哪一项属于常见误区？', '["Vue 响应式会自动绕过登录和权限校验，因此不需要鉴权设计","Vue 响应式能够让状态变化自动驱动界面更新","常见应用场景包括筛选条件变化后刷新题目列表","理解 ref/reactive 有助于掌握 Vue 响应式 的核心用法"]', '["Vue 响应式会自动绕过登录和权限校验，因此不需要鉴权设计"]', 4, 'bulk-choice-20260506') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('bulk-single-0425', 'teacher-1', '前端', 'Vue 响应式', '易', 'single', '扩展单选：在教师端维护题库时，Vue 响应式带来的主要价值是？', '["让所有题目自动变成满分答案。","强制删除学生的历史答题记录。","完全替代数据库和接口设计。","帮助教师端功能保持结构清晰，并降低后续维护成本。"]', '["帮助教师端功能保持结构清晰，并降低后续维护成本。"]', 4, 'bulk-choice-20260506') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('bulk-single-0426', 'teacher-1', '前端', 'Vue 响应式', '中', 'single', '扩展单选：使用Vue 响应式时更合理的工程做法是？', '["把所有页面逻辑都写进一个超长函数。","只在出现线上故障后再补充异常处理。","使用 Vue 响应式 时应结合边界条件、异常处理和输入校验","不做输入校验，直接信任所有客户端数据。"]', '["使用 Vue 响应式 时应结合边界条件、异常处理和输入校验"]', 4, 'bulk-choice-20260506') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('bulk-single-0427', 'teacher-1', '前端', 'Vue 响应式', '易', 'single', '扩展单选：Vue 响应式与在线考试业务结合时，优先关注什么？', '["优先把所有账号密码写在页面脚本中。","优先关注角色权限、数据一致性、异常提示和可追踪日志。","优先隐藏所有错误信息，使用户无法判断操作结果。","优先跳过后端校验，只依赖前端按钮禁用。"]', '["优先关注角色权限、数据一致性、异常提示和可追踪日志。"]', 4, 'bulk-choice-20260506') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
