INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('bulk-single-0439', 'teacher-1', '前端', 'Vue Router', '易', 'single', '扩展单选：如果要验证Vue Router实现是否可靠，最应检查哪项？', '["只检查是否删除了所有历史数据。","检查正常流程、异常流程、边界输入和权限范围是否都有覆盖。","只检查按钮颜色是否足够醒目。","只检查文件名是否足够短。"]', '["检查正常流程、异常流程、边界输入和权限范围是否都有覆盖。"]', 4, 'bulk-choice-20260506') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('bulk-single-0440', 'teacher-1', '前端', 'Vue Router', '易', 'single', '扩展单选：关于Vue Router的知识点归类，哪一项最准确？', '["Vue Router属于前端 / Vue Router相关知识点。","Vue Router只属于图片处理知识点，与软件开发无关。","Vue Router只属于线下阅卷规则，与系统实现无关。","Vue Router只属于硬件采购流程，与代码设计无关。"]', '["Vue Router属于前端 / Vue Router相关知识点。"]', 4, 'bulk-choice-20260506') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('bulk-single-0441', 'teacher-1', '前端', 'Pinia', '中', 'single', '扩展单选：Pinia的核心作用是什么？', '["StringBuilder用于高效拼接可变字符串，在循环拼接日志或 SQL 片段时可以提升实现的清晰度和稳定性。","泛型用于在编译期约束集合或方法的类型，在公共工具类和集合返回值声明时可以提升实现的清晰度和稳定性。","try-catch-finally用于捕获异常并保证必要清理逻辑执行，在文件读取、网络请求和事务处理时可以提升实现的清晰度和稳定性。","Pinia用于集中管理跨组件共享状态，在保存当前用户、菜单和考试会话信息时可以提升实现的清晰度和稳定性。"]', '["Pinia用于集中管理跨组件共享状态，在保存当前用户、菜单和考试会话信息时可以提升实现的清晰度和稳定性。"]', 4, 'bulk-choice-20260506') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('bulk-single-0442', 'teacher-1', '前端', 'Pinia', '易', 'single', '扩展单选：Pinia更适合应用在哪个场景？', '["泛型适合用于公共工具类和集合返回值声明。","try-catch-finally适合用于文件读取、网络请求和事务处理。","Pinia适合用于保存当前用户、菜单和考试会话信息。","StringBuilder适合用于循环拼接日志或 SQL 片段。"]', '["Pinia适合用于保存当前用户、菜单和考试会话信息。"]', 4, 'bulk-choice-20260506') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('bulk-single-0443', 'teacher-1', '前端', 'Pinia', '易', 'single', '扩展单选：学习Pinia时应重点理解哪一项？', '["Pinia只和页面颜色有关，与业务逻辑无关。","应重点理解 store 及其在业务代码中的使用边界。","只需要记住 Pinia 的中文名称即可，不必理解使用条件。","Pinia主要用于绕过接口参数校验。"]', '["应重点理解 store 及其在业务代码中的使用边界。"]', 4, 'bulk-choice-20260506') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('bulk-single-0444', 'teacher-1', '前端', 'Pinia', '中', 'single', '扩展单选：关于Pinia的说法，哪一项属于常见误区？', '["Pinia会自动绕过登录和权限校验，因此不需要鉴权设计","Pinia能够集中管理跨组件共享状态","常见应用场景包括保存当前用户、菜单和考试会话信息","理解 store 有助于掌握 Pinia 的核心用法"]', '["Pinia会自动绕过登录和权限校验，因此不需要鉴权设计"]', 4, 'bulk-choice-20260506') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
