INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('bulk-single-0496', 'teacher-1', '在线考试', '错题本', '易', 'single', '扩展单选：使用错题本时更合理的工程做法是？', '["使用 错题本 时应结合边界条件、异常处理和输入校验","不做输入校验，直接信任所有客户端数据。","把所有页面逻辑都写进一个超长函数。","只在出现线上故障后再补充异常处理。"]', '["使用 错题本 时应结合边界条件、异常处理和输入校验"]', 4, 'bulk-choice-20260506') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('bulk-single-0497', 'teacher-1', '在线考试', '错题本', '易', 'single', '扩展单选：错题本与在线考试业务结合时，优先关注什么？', '["优先隐藏所有错误信息，使用户无法判断操作结果。","优先跳过后端校验，只依赖前端按钮禁用。","优先把所有账号密码写在页面脚本中。","优先关注角色权限、数据一致性、异常提示和可追踪日志。"]', '["优先关注角色权限、数据一致性、异常提示和可追踪日志。"]', 4, 'bulk-choice-20260506') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('bulk-single-0498', 'teacher-1', '在线考试', '错题本', '中', 'single', '扩展单选：错题本相关实现需要避免哪种问题？', '["需要避免所有参数校验，因为校验会让功能无法运行。","需要避免接口返回明确状态，因为状态码没有意义。","需要避免职责混乱、重复代码和缺少失败分支处理。","需要避免任何日志记录，因为日志一定会导致系统不可用。"]', '["需要避免职责混乱、重复代码和缺少失败分支处理。"]', 4, 'bulk-choice-20260506') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('bulk-single-0499', 'teacher-1', '在线考试', '错题本', '易', 'single', '扩展单选：如果要验证错题本实现是否可靠，最应检查哪项？', '["只检查是否删除了所有历史数据。","检查正常流程、异常流程、边界输入和权限范围是否都有覆盖。","只检查按钮颜色是否足够醒目。","只检查文件名是否足够短。"]', '["检查正常流程、异常流程、边界输入和权限范围是否都有覆盖。"]', 4, 'bulk-choice-20260506') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('bulk-single-0500', 'teacher-1', '在线考试', '错题本', '易', 'single', '扩展单选：关于错题本的知识点归类，哪一项最准确？', '["错题本属于在线考试 / 错题本相关知识点。","错题本只属于图片处理知识点，与软件开发无关。","错题本只属于线下阅卷规则，与系统实现无关。","错题本只属于硬件采购流程，与代码设计无关。"]', '["错题本属于在线考试 / 错题本相关知识点。"]', 4, 'bulk-choice-20260506') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('bulk-multiple-0001', 'teacher-1', 'Java 基础', 'StringBuilder', '中', 'multiple', '扩展多选：关于StringBuilder的核心特征，哪些说法正确？', '["常见应用场景包括循环拼接日志或 SQL 片段","理解 append 有助于掌握 StringBuilder 的核心用法","StringBuilder会自动绕过登录和权限校验，因此不需要鉴权设计","StringBuilder只要被引入就能自动修复所有业务逻辑错误","StringBuilder能够高效拼接可变字符串"]', '["StringBuilder能够高效拼接可变字符串","常见应用场景包括循环拼接日志或 SQL 片段","理解 append 有助于掌握 StringBuilder 的核心用法"]', 4, 'bulk-choice-20260506') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('bulk-multiple-0002', 'teacher-1', 'Java 基础', 'StringBuilder', '中', 'multiple', '扩展多选：在教师端使用StringBuilder时，哪些做法更合理？', '["在在线考试系统中，StringBuilder可以帮助提升功能的可维护性","StringBuilder只能在管理员端使用，教师端和学生端完全无法复用","StringBuilder不需要任何边界处理，也不需要考虑异常情况","使用 StringBuilder 时应结合边界条件、异常处理和输入校验","StringBuilder的实现应保持职责清晰，避免把无关逻辑混在一起"]', '["使用 StringBuilder 时应结合边界条件、异常处理和输入校验","StringBuilder的实现应保持职责清晰，避免把无关逻辑混在一起","在在线考试系统中，StringBuilder可以帮助提升功能的可维护性"]', 4, 'bulk-choice-20260506') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('bulk-multiple-0003', 'teacher-1', 'Java 基础', 'StringBuilder', '中', 'multiple', '扩展多选：StringBuilder用于在线考试系统时，哪些关注点是正确的？', '["把所有用户密码展示在教师端列表中","跳过后端校验，只依赖浏览器页面限制","保持接口返回清晰，便于前端给出明确反馈","保留关键操作日志，便于后续排查和审计","结合角色权限控制，避免越权访问数据"]', '["保持接口返回清晰，便于前端给出明确反馈","保留关键操作日志，便于后续排查和审计","结合角色权限控制，避免越权访问数据"]', 4, 'bulk-choice-20260506') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
