INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('bulk-multiple-0012', 'teacher-1', 'Java 基础', '异常处理', '难', 'multiple', '扩展多选：学习try-catch-finally时，哪些判断是正确的？', '["关键点可以围绕 finally 展开复习","try-catch-finally会自动绕过登录和权限校验，因此不需要鉴权设计","try-catch-finally只要被引入就能自动修复所有业务逻辑错误","try-catch-finally用于捕获异常并保证必要清理逻辑执行，在文件读取、网络请求和事务处理时可以提升实现的清晰度和稳定性。","try-catch-finally适合用于文件读取、网络请求和事务处理。"]', '["try-catch-finally用于捕获异常并保证必要清理逻辑执行，在文件读取、网络请求和事务处理时可以提升实现的清晰度和稳定性。","try-catch-finally适合用于文件读取、网络请求和事务处理。","关键点可以围绕 finally 展开复习"]', 4, 'bulk-choice-20260506') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
