INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('bulk-multiple-0057', 'teacher-1', 'Java 并发', 'synchronized', '中', 'multiple', '扩展多选：关于synchronized的核心特征，哪些说法正确？', '["理解 synchronized 有助于掌握 synchronized 的核心用法","synchronized会自动绕过登录和权限校验，因此不需要鉴权设计","synchronized只要被引入就能自动修复所有业务逻辑错误","synchronized能够保护临界区并保证同一时刻互斥访问","常见应用场景包括库存扣减和共享计数器更新"]', '["synchronized能够保护临界区并保证同一时刻互斥访问","常见应用场景包括库存扣减和共享计数器更新","理解 synchronized 有助于掌握 synchronized 的核心用法"]', 4, 'bulk-choice-20260506') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('bulk-multiple-0058', 'teacher-1', 'Java 并发', 'synchronized', '中', 'multiple', '扩展多选：在教师端使用synchronized时，哪些做法更合理？', '["synchronized只能在管理员端使用，教师端和学生端完全无法复用","synchronized不需要任何边界处理，也不需要考虑异常情况","使用 synchronized 时应结合边界条件、异常处理和输入校验","synchronized的实现应保持职责清晰，避免把无关逻辑混在一起","在在线考试系统中，synchronized可以帮助提升功能的可维护性"]', '["使用 synchronized 时应结合边界条件、异常处理和输入校验","synchronized的实现应保持职责清晰，避免把无关逻辑混在一起","在在线考试系统中，synchronized可以帮助提升功能的可维护性"]', 4, 'bulk-choice-20260506') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
