INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('bulk-multiple-0115', 'teacher-1', 'MySQL', 'EXPLAIN', '中', 'multiple', '扩展多选：EXPLAIN用于在线考试系统时，哪些关注点是正确的？', '["保持接口返回清晰，便于前端给出明确反馈","保留关键操作日志，便于后续排查和审计","结合角色权限控制，避免越权访问数据","把所有用户密码展示在教师端列表中","跳过后端校验，只依赖浏览器页面限制"]', '["保持接口返回清晰，便于前端给出明确反馈","保留关键操作日志，便于后续排查和审计","结合角色权限控制，避免越权访问数据"]', 4, 'bulk-choice-20260506') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
