INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('bulk-multiple-0130', 'teacher-1', 'Web', 'Session', '中', 'multiple', '扩展多选：在教师端使用Session时，哪些做法更合理？', '["使用 Session 时应结合边界条件、异常处理和输入校验","Session的实现应保持职责清晰，避免把无关逻辑混在一起","在在线考试系统中，Session可以帮助提升功能的可维护性","Session只能在管理员端使用，教师端和学生端完全无法复用","Session不需要任何边界处理，也不需要考虑异常情况"]', '["使用 Session 时应结合边界条件、异常处理和输入校验","Session的实现应保持职责清晰，避免把无关逻辑混在一起","在在线考试系统中，Session可以帮助提升功能的可维护性"]', 4, 'bulk-choice-20260506') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('bulk-multiple-0131', 'teacher-1', 'Web', 'Session', '中', 'multiple', '扩展多选：Session用于在线考试系统时，哪些关注点是正确的？', '["保留关键操作日志，便于后续排查和审计","结合角色权限控制，避免越权访问数据","把所有用户密码展示在教师端列表中","跳过后端校验，只依赖浏览器页面限制","保持接口返回清晰，便于前端给出明确反馈"]', '["保持接口返回清晰，便于前端给出明确反馈","保留关键操作日志，便于后续排查和审计","结合角色权限控制，避免越权访问数据"]', 4, 'bulk-choice-20260506') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
