INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('bulk-multiple-0133', 'teacher-1', 'Web', 'JWT', '中', 'multiple', '扩展多选：关于JWT的核心特征，哪些说法正确？', '["JWT会自动绕过登录和权限校验，因此不需要鉴权设计","JWT只要被引入就能自动修复所有业务逻辑错误","JWT能够用签名令牌携带可验证的身份声明","常见应用场景包括前后端分离接口鉴权","理解 token 有助于掌握 JWT 的核心用法"]', '["JWT能够用签名令牌携带可验证的身份声明","常见应用场景包括前后端分离接口鉴权","理解 token 有助于掌握 JWT 的核心用法"]', 4, 'bulk-choice-20260506') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
