INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('bulk-multiple-0136', 'teacher-1', 'Web', 'JWT', '难', 'multiple', '扩展多选：学习JWT时，哪些判断是正确的？', '["JWT适合用于前后端分离接口鉴权。","关键点可以围绕 token 展开复习","JWT会自动绕过登录和权限校验，因此不需要鉴权设计","JWT只要被引入就能自动修复所有业务逻辑错误","JWT用于用签名令牌携带可验证的身份声明，在前后端分离接口鉴权时可以提升实现的清晰度和稳定性。"]', '["JWT用于用签名令牌携带可验证的身份声明，在前后端分离接口鉴权时可以提升实现的清晰度和稳定性。","JWT适合用于前后端分离接口鉴权。","关键点可以围绕 token 展开复习"]', 4, 'bulk-choice-20260506') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('bulk-multiple-0137', 'teacher-1', 'Web', 'CORS', '中', 'multiple', '扩展多选：关于CORS的核心特征，哪些说法正确？', '["理解 Access-Control-Allow-Origin 有助于掌握 CORS 的核心用法","CORS会自动绕过登录和权限校验，因此不需要鉴权设计","CORS只要被引入就能自动修复所有业务逻辑错误","CORS能够控制浏览器跨域请求是否被允许","常见应用场景包括前端开发服务器访问后端 API"]', '["CORS能够控制浏览器跨域请求是否被允许","常见应用场景包括前端开发服务器访问后端 API","理解 Access-Control-Allow-Origin 有助于掌握 CORS 的核心用法"]', 4, 'bulk-choice-20260506') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
