INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('bulk-multiple-0139', 'teacher-1', 'Web', 'CORS', '中', 'multiple', '扩展多选：CORS用于在线考试系统时，哪些关注点是正确的？', '["跳过后端校验，只依赖浏览器页面限制","保持接口返回清晰，便于前端给出明确反馈","保留关键操作日志，便于后续排查和审计","结合角色权限控制，避免越权访问数据","把所有用户密码展示在教师端列表中"]', '["保持接口返回清晰，便于前端给出明确反馈","保留关键操作日志，便于后续排查和审计","结合角色权限控制，避免越权访问数据"]', 4, 'bulk-choice-20260506') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('bulk-multiple-0140', 'teacher-1', 'Web', 'CORS', '难', 'multiple', '扩展多选：学习CORS时，哪些判断是正确的？', '["CORS用于控制浏览器跨域请求是否被允许，在前端开发服务器访问后端 API时可以提升实现的清晰度和稳定性。","CORS适合用于前端开发服务器访问后端 API。","关键点可以围绕 Access-Control-Allow-Origin 展开复习","CORS会自动绕过登录和权限校验，因此不需要鉴权设计","CORS只要被引入就能自动修复所有业务逻辑错误"]', '["CORS用于控制浏览器跨域请求是否被允许，在前端开发服务器访问后端 API时可以提升实现的清晰度和稳定性。","CORS适合用于前端开发服务器访问后端 API。","关键点可以围绕 Access-Control-Allow-Origin 展开复习"]', 4, 'bulk-choice-20260506') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('bulk-multiple-0141', 'teacher-1', 'Web', 'RESTful API', '中', 'multiple', '扩展多选：关于RESTful API的核心特征，哪些说法正确？', '["常见应用场景包括题库、试卷和考试的增删改查接口","理解 GET/POST/PUT/DELETE 有助于掌握 RESTful API 的核心用法","RESTful API会自动绕过登录和权限校验，因此不需要鉴权设计","RESTful API只要被引入就能自动修复所有业务逻辑错误","RESTful API能够用资源路径和 HTTP 方法表达接口语义"]', '["RESTful API能够用资源路径和 HTTP 方法表达接口语义","常见应用场景包括题库、试卷和考试的增删改查接口","理解 GET/POST/PUT/DELETE 有助于掌握 RESTful API 的核心用法"]', 4, 'bulk-choice-20260506') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('bulk-multiple-0142', 'teacher-1', 'Web', 'RESTful API', '中', 'multiple', '扩展多选：在教师端使用RESTful API时，哪些做法更合理？', '["在在线考试系统中，RESTful API可以帮助提升功能的可维护性","RESTful API只能在管理员端使用，教师端和学生端完全无法复用","RESTful API不需要任何边界处理，也不需要考虑异常情况","使用 RESTful API 时应结合边界条件、异常处理和输入校验","RESTful API的实现应保持职责清晰，避免把无关逻辑混在一起"]', '["使用 RESTful API 时应结合边界条件、异常处理和输入校验","RESTful API的实现应保持职责清晰，避免把无关逻辑混在一起","在在线考试系统中，RESTful API可以帮助提升功能的可维护性"]', 4, 'bulk-choice-20260506') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
