INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('bulk-multiple-0144', 'teacher-1', 'Web', 'RESTful API', '难', 'multiple', '扩展多选：学习RESTful API时，哪些判断是正确的？', '["RESTful API只要被引入就能自动修复所有业务逻辑错误","RESTful API用于用资源路径和 HTTP 方法表达接口语义，在题库、试卷和考试的增删改查接口时可以提升实现的清晰度和稳定性。","RESTful API适合用于题库、试卷和考试的增删改查接口。","关键点可以围绕 GET/POST/PUT/DELETE 展开复习","RESTful API会自动绕过登录和权限校验，因此不需要鉴权设计"]', '["RESTful API用于用资源路径和 HTTP 方法表达接口语义，在题库、试卷和考试的增删改查接口时可以提升实现的清晰度和稳定性。","RESTful API适合用于题库、试卷和考试的增删改查接口。","关键点可以围绕 GET/POST/PUT/DELETE 展开复习"]', 4, 'bulk-choice-20260506') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('bulk-multiple-0145', 'teacher-1', 'Spring', 'IoC', '中', 'multiple', '扩展多选：关于IoC 容器的核心特征，哪些说法正确？', '["IoC 容器能够统一创建和装配对象依赖","常见应用场景包括Service、Repository 和 Controller 协作","理解 @Autowired 有助于掌握 IoC 容器 的核心用法","IoC 容器会自动绕过登录和权限校验，因此不需要鉴权设计","IoC 容器只要被引入就能自动修复所有业务逻辑错误"]', '["IoC 容器能够统一创建和装配对象依赖","常见应用场景包括Service、Repository 和 Controller 协作","理解 @Autowired 有助于掌握 IoC 容器 的核心用法"]', 4, 'bulk-choice-20260506') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('bulk-multiple-0146', 'teacher-1', 'Spring', 'IoC', '中', 'multiple', '扩展多选：在教师端使用IoC 容器时，哪些做法更合理？', '["IoC 容器的实现应保持职责清晰，避免把无关逻辑混在一起","在在线考试系统中，IoC 容器可以帮助提升功能的可维护性","IoC 容器只能在管理员端使用，教师端和学生端完全无法复用","IoC 容器不需要任何边界处理，也不需要考虑异常情况","使用 IoC 容器 时应结合边界条件、异常处理和输入校验"]', '["使用 IoC 容器 时应结合边界条件、异常处理和输入校验","IoC 容器的实现应保持职责清晰，避免把无关逻辑混在一起","在在线考试系统中，IoC 容器可以帮助提升功能的可维护性"]', 4, 'bulk-choice-20260506') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
