INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('bulk-multiple-0160', 'teacher-1', 'Spring', '事务传播', '难', 'multiple', '扩展多选：学习事务传播行为时，哪些判断是正确的？', '["事务传播行为用于定义方法嵌套调用时事务如何参与或新建，在下单、扣库存和写日志的一致性控制时可以提升实现的清晰度和稳定性。","事务传播行为适合用于下单、扣库存和写日志的一致性控制。","关键点可以围绕 Propagation 展开复习","事务传播行为会自动绕过登录和权限校验，因此不需要鉴权设计","事务传播行为只要被引入就能自动修复所有业务逻辑错误"]', '["事务传播行为用于定义方法嵌套调用时事务如何参与或新建，在下单、扣库存和写日志的一致性控制时可以提升实现的清晰度和稳定性。","事务传播行为适合用于下单、扣库存和写日志的一致性控制。","关键点可以围绕 Propagation 展开复习"]', 4, 'bulk-choice-20260506') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
