INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('bulk-multiple-0188', 'teacher-1', '前端', 'Promise', '难', 'multiple', '扩展多选：学习Promise时，哪些判断是正确的？', '["Promise会自动绕过登录和权限校验，因此不需要鉴权设计","Promise只要被引入就能自动修复所有业务逻辑错误","Promise用于表达异步操作最终成功或失败的结果，在请求 API 后更新页面状态时可以提升实现的清晰度和稳定性。","Promise适合用于请求 API 后更新页面状态。","关键点可以围绕 then/catch 展开复习"]', '["Promise用于表达异步操作最终成功或失败的结果，在请求 API 后更新页面状态时可以提升实现的清晰度和稳定性。","Promise适合用于请求 API 后更新页面状态。","关键点可以围绕 then/catch 展开复习"]', 4, 'bulk-choice-20260506') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
