INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('question-bank-0001', 'teacher-1', 'Java', 'StringBuilder', '易', 'single', '关于 StringBuilder 的描述，哪一项最准确？', '["适合在循环或多次拼接场景下构造可变字符串。","用于显式表达某个值可能为空，减少直接判空的嵌套代码。","是 Spring MVC 的前端控制器，负责统一接收请求并分发到处理器。","用于在一维方向上高效完成子元素对齐、分配与伸缩。"]', '["适合在循环或多次拼接场景下构造可变字符串。"]', 4, 'generated-bank-20260430') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
