INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('question-bank-0081', 'teacher-1', 'Java 并发', 'ThreadPoolExecutor', '易', 'single', '关于 线程池 的描述，哪一项最准确？', '["用于复用线程并统一管理异步任务的提交、排队与执行。","用于统一管理对象创建、装配和生命周期，降低组件之间的耦合度。","用于以左表为基准关联右表，即使右表无匹配记录也保留左表数据。","用于描述对象结构、函数签名或类契约，提高代码可读性与类型约束。"]', '["用于复用线程并统一管理异步任务的提交、排队与执行。"]', 4, 'generated-bank-20260430') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
