INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('question-bank-0091', 'teacher-1', 'Java 并发', 'synchronized', '易', 'single', '关于 synchronized 的描述，哪一项最准确？', '["用于把日志、事务、鉴权等横切关注点从业务代码中抽离出来。","用于通过更有语义的元素结构表达页面区域与内容角色。","用于在保持类型约束的同时编写可复用的函数、接口与组件。","用于在共享资源访问前加锁，保证同一时刻只有一个线程进入临界区。"]', '["用于把日志、事务、鉴权等横切关注点从业务代码中抽离出来。"]', 4, 'generated-bank-20260430') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
