INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('question-bank-0101', 'teacher-1', 'Java 并发', 'ReentrantLock', '易', 'single', '关于 ReentrantLock 的描述，哪一项最准确？', '["用于在浏览器层面对输入内容做必填、格式和范围等基础检查。","用于在多种可能类型之间通过条件判断缩小当前分支的实际类型。","提供比内置锁更灵活的显式加锁与解锁控制能力。","用于按场景打包常见依赖与默认配置，简化项目集成过程。"]', '["用于在浏览器层面对输入内容做必填、格式和范围等基础检查。"]', 4, 'generated-bank-20260430') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('question-bank-0102', 'teacher-1', 'Java 并发', 'ReentrantLock', '中', 'multiple', '关于 ReentrantLock 的特点，下列哪些说法正确？', '["适合需要更细粒度控制的同步场景","ReentrantLock 获取锁后无需在 finally 中释放，也不会影响后续线程。","需要手动调用 lock 与 unlock","支持 tryLock 等更灵活的获取方式"]', '["需要手动调用 lock 与 unlock","支持 tryLock 等更灵活的获取方式","适合需要更细粒度控制的同步场景"]', 4, 'generated-bank-20260430') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
