INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('question-bank-0111', 'teacher-1', 'Java 并发', 'volatile', '易', 'single', '关于 volatile 的描述，哪一项最准确？', '["用于基于已有响应式数据派生新值，并在依赖不变时缓存计算结果。","用于保证共享变量的可见性，避免线程读取到过期值。","是 Spring MVC 的前端控制器，负责统一接收请求并分发到处理器。","用于在一维方向上高效完成子元素对齐、分配与伸缩。"]', '["用于基于已有响应式数据派生新值，并在依赖不变时缓存计算结果。"]', 4, 'generated-bank-20260430') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
