INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('question-bank-0161', 'teacher-1', 'Spring', 'AOP', '易', 'single', '关于 AOP 切面 的描述，哪一项最准确？', '["用于把日志、事务、鉴权等横切关注点从业务代码中抽离出来。","用于把 Java 方法与 SQL 语句映射起来，简化持久层访问代码。","用于把多个子元素的事件处理绑定到公共父元素上，减少重复监听器。","用于按逻辑关注点组织组件代码，提高复用性与可维护性。"]', '["用于把日志、事务、鉴权等横切关注点从业务代码中抽离出来。"]', 4, 'generated-bank-20260430') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
