INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('question-bank-0171', 'teacher-1', 'Spring Boot', 'Starter', '易', 'single', '关于 Starter 依赖 的描述，哪一项最准确？', '["用于提升基于索引列的查询效率，并支持范围查询等访问模式。","用于让函数在离开定义环境后仍然访问其词法作用域中的变量。","用于自动收集副作用中访问到的响应式依赖，并在依赖变化时重新执行。","用于按场景打包常见依赖与默认配置，简化项目集成过程。"]', '["用于提升基于索引列的查询效率，并支持范围查询等访问模式。"]', 4, 'generated-bank-20260430') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
