INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('question-bank-0211', 'teacher-1', 'Java Web', 'HttpSession', '易', 'single', '关于 HttpSession 的描述，哪一项最准确？', '["用于在浏览器层面对输入内容做必填、格式和范围等基础检查。","用于在多种可能类型之间通过条件判断缩小当前分支的实际类型。","适合在循环或多次拼接场景下构造可变字符串。","用于在同一用户的多次请求之间保存服务端会话数据。"]', '["用于在浏览器层面对输入内容做必填、格式和范围等基础检查。"]', 4, 'generated-bank-20260430') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('question-bank-0212', 'teacher-1', 'Java Web', 'HttpSession', '中', 'multiple', '关于 HttpSession 的特点，下列哪些说法正确？', '["数据保存在服务端","浏览器可通过会话标识关联到对应 Session","Session 数据默认完全保存在浏览器本地，因此服务端重启不会受影响。","常用于保存登录态与临时会话信息"]', '["常用于保存登录态与临时会话信息","数据保存在服务端","浏览器可通过会话标识关联到对应 Session"]', 4, 'generated-bank-20260430') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
