INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('question-bank-0301', 'teacher-1', 'CSS3', 'Grid', '易', 'single', '关于 Grid 布局 的描述，哪一项最准确？', '["用于在请求处理链中分层组织通用逻辑，如鉴权、日志、解析与异常处理。","用于在共享资源访问前加锁，保证同一时刻只有一个线程进入临界区。","用于在二维行列体系中组织页面区块，更适合复杂面板布局。","用于描述对象结构、函数签名或类契约，提高代码可读性与类型约束。"]', '["用于在请求处理链中分层组织通用逻辑，如鉴权、日志、解析与异常处理。"]', 4, 'generated-bank-20260430') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
