INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('question-bank-0321', 'teacher-1', 'JavaScript', 'Promise', '易', 'single', '关于 Promise 的描述，哪一项最准确？', '["用于表示一个异步操作最终完成或失败的结果，并组织后续回调。","用于在多种可能类型之间通过条件判断缩小当前分支的实际类型。","适合在循环或多次拼接场景下构造可变字符串。","用于保证共享变量的可见性，避免线程读取到过期值。"]', '["用于表示一个异步操作最终完成或失败的结果，并组织后续回调。"]', 4, 'generated-bank-20260430') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
