INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('question-bank-0332', 'teacher-1', 'JavaScript', 'async/await', '中', 'multiple', '关于 async/await 的特点，下列哪些说法正确？', '["有助于减少 then 嵌套","通常与 try/catch 配合处理异常","使用 await 后，整个浏览器线程会被完全挂起，页面无法继续处理任何任务。","await 只能出现在 async 函数中"]', '["await 只能出现在 async 函数中","有助于减少 then 嵌套","通常与 try/catch 配合处理异常"]', 4, 'generated-bank-20260430') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
