INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('question-bank-0361', 'teacher-1', 'JavaScript', 'Fetch 与 CORS', '易', 'single', '关于 Fetch API 的描述，哪一项最准确？', '["用于在浏览器中发起网络请求，并通过 Promise 获取响应结果。","用于把基础类型或对象包装为带有响应式 value 的引用。","用于按键值对组织数据，支持根据 key 快速查找 value。","用于统一管理对象创建、装配和生命周期，降低组件之间的耦合度。"]', '["用于在浏览器中发起网络请求，并通过 Promise 获取响应结果。"]', 4, 'generated-bank-20260430') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
