INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('question-bank-0371', 'teacher-1', 'TypeScript', 'interface', '易', 'single', '关于 interface 的描述，哪一项最准确？', '["用于把对象包装为响应式代理，便于统一管理多字段状态。","用于存放不重复元素，本质上依赖哈希结构实现去重。","用于把日志、事务、鉴权等横切关注点从业务代码中抽离出来。","用于描述对象结构、函数签名或类契约，提高代码可读性与类型约束。"]', '["用于把对象包装为响应式代理，便于统一管理多字段状态。"]', 4, 'generated-bank-20260430') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
