INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('question-bank-0381', 'teacher-1', 'TypeScript', '泛型', '易', 'single', '关于 TypeScript 泛型 的描述，哪一项最准确？', '["用于以声明式方式完成集合的过滤、映射、聚合等操作。","用于按场景打包常见依赖与默认配置，简化项目集成过程。","用于在保持类型约束的同时编写可复用的函数、接口与组件。","用于按逻辑关注点组织组件代码，提高复用性与可维护性。"]', '["用于以声明式方式完成集合的过滤、映射、聚合等操作。"]', 4, 'generated-bank-20260430') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
