INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('question-bank-0391', 'teacher-1', 'TypeScript', '联合类型收窄', '易', 'single', '关于 联合类型收窄 的描述，哪一项最准确？', '["是 Spring MVC 的前端控制器，负责统一接收请求并分发到处理器。","用于在多种可能类型之间通过条件判断缩小当前分支的实际类型。","用于自动收集副作用中访问到的响应式依赖，并在依赖变化时重新执行。","用于显式表达某个值可能为空，减少直接判空的嵌套代码。"]', '["是 Spring MVC 的前端控制器，负责统一接收请求并分发到处理器。"]', 4, 'generated-bank-20260430') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
