INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('question-bank-0401', 'teacher-1', 'Vue 2', 'computed', '易', 'single', '关于 computed 计算属性 的描述，哪一项最准确？', '["用于基于已有响应式数据派生新值，并在依赖不变时缓存计算结果。","用于协调同步代码、宏任务与微任务的执行顺序，是 Node.js 异步模型的核心。","用于复用线程并统一管理异步任务的提交、排队与执行。","用于在请求进入 Servlet 前后执行通用预处理或后处理逻辑。"]', '["用于基于已有响应式数据派生新值，并在依赖不变时缓存计算结果。"]', 4, 'generated-bank-20260430') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('question-bank-0402', 'teacher-1', 'Vue 2', 'computed', '中', 'multiple', '关于 computed 计算属性 的特点，下列哪些说法正确？', '["依赖变化时才会重新计算","适合模板中复杂展示逻辑","比在模板里写长表达式更易维护","computed 每次渲染都会无条件重新执行，因此和 methods 完全一样。"]', '["依赖变化时才会重新计算","适合模板中复杂展示逻辑","比在模板里写长表达式更易维护"]', 4, 'generated-bank-20260430') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
