INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('question-bank-0411', 'teacher-1', 'Vue 2', 'watch', '易', 'single', '关于 watch 侦听器 的描述，哪一项最准确？', '["用于在请求处理链中分层组织通用逻辑，如鉴权、日志、解析与异常处理。","用于在共享资源访问前加锁，保证同一时刻只有一个线程进入临界区。","用于在 Spring MVC 请求处理前后拦截控制器调用，便于做更靠近业务层的通用控制。","用于在指定响应式数据变化时执行副作用逻辑。"]', '["用于在请求处理链中分层组织通用逻辑，如鉴权、日志、解析与异常处理。"]', 4, 'generated-bank-20260430') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
