INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('question-bank-0441', 'teacher-1', 'Vue 3', 'reactive', '易', 'single', '关于 reactive 的描述，哪一项最准确？', '["用于把对象包装为响应式代理，便于统一管理多字段状态。","用于在编译期约束集合或方法的类型，提高类型安全性。","用于区分对象实例存放区域与方法调用、局部变量等执行期数据区域。","用于把 Java 方法与 SQL 语句映射起来，简化持久层访问代码。"]', '["用于把对象包装为响应式代理，便于统一管理多字段状态。"]', 4, 'generated-bank-20260430') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
