INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('question-bank-0451', 'teacher-1', 'Vue 3', 'Composition API', '易', 'single', '关于 Composition API 的描述，哪一项最准确？', '["用于保证对象在集合判等和哈希散列场景中的一致行为。","用于在类加载时优先委托父加载器，避免基础类被重复加载或被错误替换。","用于提升基于索引列的查询效率，并支持范围查询等访问模式。","用于按逻辑关注点组织组件代码，提高复用性与可维护性。"]', '["用于保证对象在集合判等和哈希散列场景中的一致行为。"]', 4, 'generated-bank-20260430') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
