INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('question-bank-0461', 'teacher-1', 'Vue 3', 'watchEffect', '易', 'single', '关于 watchEffect 的描述，哪一项最准确？', '["用于从 GC Roots 出发判断对象是否仍可被访问，从而决定是否可回收。","用于平衡并发读取一致性与系统吞吐之间的关系。","用于自动收集副作用中访问到的响应式依赖，并在依赖变化时重新执行。","基于动态数组实现，适合高频随机访问与顺序遍历。"]', '["用于从 GC Roots 出发判断对象是否仍可被访问，从而决定是否可回收。"]', 4, 'generated-bank-20260430') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('question-bank-0462', 'teacher-1', 'Vue 3', 'watchEffect', '中', 'multiple', '关于 watchEffect 的特点，下列哪些说法正确？', '["在副作用里读取到哪些响应式值就会跟踪哪些值","watchEffect 只会在组件创建时执行一次，后续依赖变化不会再次触发。","不需要手动指定依赖源","适合快速响应多个依赖的副作用逻辑"]', '["不需要手动指定依赖源","适合快速响应多个依赖的副作用逻辑","在副作用里读取到哪些响应式值就会跟踪哪些值"]', 4, 'generated-bank-20260430') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
