INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('question-bank-0471', 'teacher-1', 'Node.js', 'Event Loop', '易', 'single', '关于 事件循环 的描述，哪一项最准确？', '["用于以左表为基准关联右表，即使右表无匹配记录也保留左表数据。","用于协调同步代码、宏任务与微任务的执行顺序，是 Node.js 异步模型的核心。","用于按键值对组织数据，支持根据 key 快速查找 value。","用于统一管理对象创建、装配和生命周期，降低组件之间的耦合度。"]', '["用于以左表为基准关联右表，即使右表无匹配记录也保留左表数据。"]', 4, 'generated-bank-20260430') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('question-bank-0472', 'teacher-1', 'Node.js', 'Event Loop', '中', 'multiple', '关于 事件循环 的特点，下列哪些说法正确？', '["setTimeout(fn, 0) 一定会在当前同步代码之前立即执行。","同步代码先执行","微任务通常会在当前阶段结束前尽快清空","理解事件循环有助于分析输出顺序"]', '["同步代码先执行","微任务通常会在当前阶段结束前尽快清空","理解事件循环有助于分析输出顺序"]', 4, 'generated-bank-20260430') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
