INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('question-bank-0481', 'teacher-1', 'Node.js', 'Express 中间件', '易', 'single', '关于 Express 中间件 的描述，哪一项最准确？', '["用于在请求处理链中分层组织通用逻辑，如鉴权、日志、解析与异常处理。","用于存放不重复元素，本质上依赖哈希结构实现去重。","用于把日志、事务、鉴权等横切关注点从业务代码中抽离出来。","用于通过更有语义的元素结构表达页面区域与内容角色。"]', '["用于在请求处理链中分层组织通用逻辑，如鉴权、日志、解析与异常处理。"]', 4, 'generated-bank-20260430') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
INSERT INTO question (id, teacher_id, subject, knowledge_point, difficulty, type, title, options_json, answer_json, score, source_tag) VALUES ('question-bank-0482', 'teacher-1', 'Node.js', 'Express 中间件', '中', 'multiple', '关于 Express 中间件 的特点，下列哪些说法正确？', '["可以通过 next 继续传递请求","适合统一日志和权限校验","可按路径或全局注册","Express 中间件执行后不能再交给后续处理器，因此不能形成链式调用。"]', '["可以通过 next 继续传递请求","适合统一日志和权限校验","可按路径或全局注册"]', 4, 'generated-bank-20260430') ON DUPLICATE KEY UPDATE teacher_id=VALUES(teacher_id), subject=VALUES(subject), knowledge_point=VALUES(knowledge_point), difficulty=VALUES(difficulty), type=VALUES(type), title=VALUES(title), options_json=VALUES(options_json), answer_json=VALUES(answer_json), score=VALUES(score), source_tag=VALUES(source_tag);
